    this.shadow = this.attachShadow({ mode: "open" });
  }

  connectedCallback(): void {
    this.render();
    this.setupHandlers();
    this.showDialog();
  }

  /**
   * Register a callback invoked when login succeeds.
   */
  setLoginCallback(cb: (username: string, token: string) => void): void {
    this.onLoginSuccess = cb;
  }

  /** Show the modal dialog. */
  showDialog(): void {
    const dialog = this.shadow.querySelector("dialog") as HTMLDialogElement | null;
    if (dialog && !dialog.open) {
      dialog.showModal();
    }
  }

  /** Hide the modal dialog. */
  hideDialog(): void {
    const dialog = this.shadow.querySelector("dialog") as HTMLDialogElement | null;
    if (dialog && dialog.open) {
      dialog.close();
    }
  }

  private render(): void {
    this.shadow.innerHTML = `
