          width: 100%;
          padding: 0.6rem 0.8rem;
          border: 2px solid #d0d0d0;
          border-radius: 6px;
          font-size: 1rem;
          margin-bottom: 1rem;
          box-sizing: border-box;
          transition: border-color 0.2s;
        }

        input[type="text"]:focus {
          outline: none;
          border-color: #4a6fa5;
        }

        button {
          width: 100%;
          padding: 0.7rem;
          background: #4a6fa5;
          color: white;
          border: none;
          border-radius: 6px;
          font-size: 1rem;
          cursor: pointer;
          font-weight: 600;
          transition: background 0.2s;
        }

        button:hover {
          background: #3a5a8a;
        }

        button:disabled {
          background: #a0aec0;
          cursor: not-allowed;
