private insertFormatting(format: string): void {
  const ta = this.q<HTMLTextAreaElement>("[data-cy='post-input']");
  const start = ta.selectionStart;
  const end = ta.selectionEnd;
  const selected = ta.value.substring(start, end);
  let before = "";
  let after = "";
  let cursor = 0;

  switch (format) {
    case "bold":
      before = "**";
      after = "**";
      cursor = selected ? end + 4 : start + 2;
      break;
    case "italic":
      before = "*";
      after = "*";
      cursor = selected ? end + 2 : start + 1;
      break;
    case "link":
      if (selected) {
        ta.value = ta.value.substring(0, start) + `[${selected}](url)` + ta.value.substring(end);
        ta.selectionStart = ta.selectionEnd = start + selected.length + 3;
      } else {
        ta.value = ta.value.substring(0, start) + "[](url)" + ta.value.substring(end);
        ta.selectionStart = ta.selectionEnd = start + 1;
      }
      ta.focus();
      return;
  }

  ta.value =
    ta.value.substring(0, start) +
    before +
    selected +
    after +
    ta.value.substring(end);
  ta.selectionStart = ta.selectionEnd = cursor;
  ta.focus();
}

