import { slog } from "./slog";
import "./components/login-modal";
import "./components/app-shell";

/**
 * Declare names and types of environment variables.
 */
declare const process: {
  env: {
    DATABASE_HOST: string;
    DATABASE_PATH: string;
    AUTH_PATH: string;
  };
};

/**
 * Entry point of the application.
 * Wires up the login modal with the app shell.
 */
function main(): void {
  slog.info("Using database", [
    "database",
    `${process.env.DATABASE_HOST}${process.env.DATABASE_PATH}`,
  ]);

  const loginModal = document.querySelector("login-modal") as HTMLElement & {
    setLoginCallback: (cb: (username: string, token: string) => void) => void;
    showDialog: () => void;
  };

  const appShell = document.querySelector("app-shell") as HTMLElement & {
    setUser: (username: string, token: string) => void;
    setLogoutCallback: (cb: () => void) => void;
  };

  if (!loginModal || !appShell) {
    slog.error("Could not find required elements", [
      "loginModal",
      !!loginModal,
      "appShell",
      !!appShell,
    ]);
    return;
  }

  // When login succeeds, configure the app shell
  loginModal.setLoginCallback((username: string, token: string) => {
    appShell.setUser(username, token);
  });

  // When logout is triggered by app shell, show login modal again
  appShell.setLogoutCallback(() => {
    loginModal.showDialog();
  });
}

document.addEventListener("DOMContentLoaded", () => {
  main();
});

/* Global styles */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  height: 100%;
  overflow: hidden;
  background: #1e1e2e;
  color: #cdd6f4;
  font-family: "Segoe UI", system-ui, -apple-system, sans-serif;
  font-size: 16px;
}

app-shell {
  display: flex;
  flex-direction: column;
  height: 100vh;
}

login-modal {
  /* Login modal sits above the app shell */
  position: relative;
  z-index: 1000;
}

/// <reference types="cypress" />

declare namespace Cypress {
  interface Chainable {
    login(username: string): Chainable<void>;
    logout(): Chainable<void>;
    openWorkspace(workspace: string): Chainable<void>;
    createWorkspace(workspace: string): Chainable<void>;
    deleteWorkspace(workspace: string): Chainable<void>;
    openChannel(channel: string): Chainable<void>;
    createChannel(channel: string): Chainable<void>;
    deleteChannel(channel: string): Chainable<void>;
    createPost(post: string): Chainable<void>;
    getPost(post: string): Chainable<JQuery<Element>>;
    replyToPost(reply: string): Chainable<void>;
    reactToPost(reaction: string): Chainable<void>;
  }
}

/**
 * Login using given username.
 * Assumes that no one is currently logged in (login modal is showing).
 */
Cypress.Commands.add("login", (username: string) => {
  cy.get("[data-cy='username-input']").type(username);
  cy.get("[data-cy='login-btn']").click();
  // Wait for the username to appear in the header
  cy.get("[data-cy='current-user']").should("have.text", username);
});

/**
 * Logout the currently logged in user.
 * Assumes that a user is currently logged in.
 */
Cypress.Commands.add("logout", () => {
  cy.get("[data-cy='logout-btn']").click();
  // Wait for the login modal input to reappear
  cy.get("[data-cy='username-input']").should("be.visible");
});

/**
 * Open a workspace.
 * Assumes someone is logged in and the workspace exists.
 */
Cypress.Commands.add("openWorkspace", (workspace: string) => {
  cy.contains("[data-cy='workspace-open']", workspace).click();
  cy.contains(workspace).should("exist");
});

/**
 * Create a workspace.
 * Assumes someone is logged in and the workspace does not exist.
 */
Cypress.Commands.add("createWorkspace", (workspace: string) => {
  cy.get("[data-cy='workspace-input']").type(workspace);
  cy.get("[data-cy='workspace-create-btn']").click();
});

/**
 * Delete a workspace.
 * Assumes someone is logged in and the workspace exists.
 */
Cypress.Commands.add("deleteWorkspace", (workspace: string) => {
  cy.get(`[data-cy='workspace-delete'][data-name="${workspace}"]`).click();
});

/**
 * Open a channel.
 * Assumes someone is logged in, a workspace is open, and the channel exists.
 */
Cypress.Commands.add("openChannel", (channel: string) => {
  cy.contains("[data-cy='channel-open']", channel).click();
  cy.contains(channel).should("exist");
});

/**
 * Create a channel.
 * Assumes someone is logged in, a workspace is open, and the channel does not exist.
 */
Cypress.Commands.add("createChannel", (channel: string) => {
  cy.get("[data-cy='channel-input']").type(channel);
  cy.get("[data-cy='channel-create-btn']").click();
});

/**
 * Delete a channel.
 * Assumes someone is logged in, a workspace is open, and the channel exists.
 */
Cypress.Commands.add("deleteChannel", (channel: string) => {
  cy.get(`[data-cy='channel-delete'][data-name="${channel}"]`).click();
});

/**
 * Create a post.
 * Assumes someone is logged in, a workspace is open, and a channel is open.
 */
Cypress.Commands.add("createPost", (post: string) => {
  cy.get("[data-cy='post-input']").type(post);
  cy.get("[data-cy='post-btn']").click();
});

/**
 * Get a post element that contains the given search text.
 * Returns the enclosing post element.
 */
Cypress.Commands.add(
  "getPost",
  (searchText: string): Cypress.Chainable<JQuery<Element>> => {
    return cy
      .contains("[data-cy='post-content']", searchText)
      .closest("[data-cy='post-item']");
  },
);

/**
 * Reply to a post (prevSubject from getPost).
 * Clicks the reply button on the post, types the reply, and submits.
 */
Cypress.Commands.add(
  "replyToPost",
  { prevSubject: true },
  (subject, reply: string) => {
    cy.wrap(subject).find("[data-cy='reply-btn']").click();
    cy.get("[data-cy='post-input']").type(reply);
    cy.get("[data-cy='post-btn']").click();
  },
);

/**
 * React to a post (prevSubject from getPost).
 * Clicks the reaction button for the given reaction name.
 */
Cypress.Commands.add(
  "reactToPost",
  { prevSubject: true },
  (subject, reaction: string) => {
    cy.wrap(subject).find(`[data-reaction="${reaction}"]`).click();
  },
);

