    34→// ---- Reaction definitions ----
    35→
    36→const REACTIONS = [
    37→  { name: ":smile:", icon: "mdi:emoticon-happy-outline", label: "smile" },
    38→  { name: ":frown:", icon: "mdi:emoticon-sad-outline", label: "frown" },
    39→  { name: ":like:", icon: "mdi:thumb-up-outline", label: "like" },
    40→  { name: ":celebrate:", icon: "mdi:party-popper", label: "celebrate" },
    41→];
    42→
    43→const REACTION_ICON_MAP: Record<string, string> = {
    44→  smile: "mdi:emoticon-happy-outline",
    45→  frown: "mdi:emoticon-sad-outline",
    46→  like: "mdi:thumb-up-outline",
