    50→};
    51→
    52→// ---- Markdown / text rendering ----
    53→
    54→function escapeHtml(text: string): string {
    55→  return text
    56→    .replace(/&/g, "&amp;")
    57→    .replace(/</g, "&lt;")
    58→    .replace(/>/g, "&gt;")
    59→    .replace(/"/g, "&quot;")
    60→    .replace(/'/g, "&#39;");
    61→}
    62→
    63→function renderMarkdown(raw: string): string {
    64→  let i = 0;
    65→  let out = "";
    66→
    67→  while (i < raw.length) {
    68→    // Bold: **...**
    69→    if (raw.startsWith("**", i)) {
    70→      const end = raw.indexOf("**", i + 2);
    71→      if (end !== -1) {
    72→        out += `<strong>${escapeHtml(raw.substring(i + 2, end))}</strong>`;
    73→        i = end + 2;
    74→        continue;
    75→      }
    76→    }
    77→
    78→    // Italic: *...*  (not **)
    79→    if (raw[i] === "*" && raw[i + 1] !== "*") {
    80→      let end = raw.indexOf("*", i + 1);
    81→      while (end !== -1 && raw[end + 1] === "*") {
    82→        end = raw.indexOf("*", end + 1);
    83→      }
    84→      if (end !== -1) {
    85→        out += `<em>${escapeHtml(raw.substring(i + 1, end))}</em>`;
    86→        i = end + 1;
    87→        continue;
    88→      }
    89→    }
    90→
    91→    // Link: [text](url)
    92→    if (raw[i] === "[") {
    93→      const closeB = raw.indexOf("]", i + 1);
    94→      if (closeB !== -1 && raw[closeB + 1] === "(") {
    95→        const closeP = raw.indexOf(")", closeB + 2);
    96→        if (closeP !== -1) {
    97→          const linkText = raw.substring(i + 1, closeB);
    98→          const url = raw.substring(closeB + 2, closeP);
    99→          if (!url.startsWith("javascript:") && !url.startsWith("data:")) {
   100→            out += `<a href="${escapeHtml(url)}" target="_blank" rel="noopener noreferrer">${escapeHtml(linkText)}</a>`;
   101→          } else {
   102→            out += escapeHtml(raw.substring(i, closeP + 1));
   103→          }
   104→          i = closeP + 1;
   105→          continue;
   106→        }
   107→      }
   108→    }
   109→
   110→    // Emoji / reaction: :name:
   111→    if (raw[i] === ":") {
   112→      const nextColon = raw.indexOf(":", i + 1);
   113→      if (nextColon !== -1) {
   114→        const name = raw.substring(i + 1, nextColon);
   115→        if (/^[a-z-]+$/.test(name)) {
   116→          const icon = REACTION_ICON_MAP[name];
   117→          if (icon) {
   118→            out += `<iconify-icon icon="${icon}" aria-label="${name}"></iconify-icon>`;
   119→            i = nextColon + 1;
   120→            continue;
   121→          }
   122→        }
   123→      }
   124→    }
   125→
   126→    // Newline
   127→    if (raw[i] === "\n") {
   128→      out += "<br>";
   129→      i++;
   130→      continue;
   131→    }
   132→
   133→    // Regular character
   134→    out += escapeHtml(raw[i]);
   135→    i++;
   136→  }
   137→
   138→  return out;
   139→}
   140→
   141→// ---- Post tree helpers ----
   142→
   143→interface PostNode {
   144→  entry: PostEntry;
   145→  children: PostNode[];
   146→}
   147→
   148→function buildPostTree(posts: Map<string, PostEntry>): PostNode[] {
   149→  const nodeMap = new Map<string, PostNode>();
   150→
   151→  for (const entry of posts.values()) {
   152→    nodeMap.set(entry.path, { entry, children: [] });
   153→  }
   154→
   155→  const roots: PostNode[] = [];
   156→
   157→  for (const [, node] of nodeMap) {
   158→    const parent = node.entry.doc.parent ?? "";
   159→    if (!parent) {
   160→      roots.push(node);
   161→    } else {
   162→      const normalizedParent = normalizePath(parent);
   163→      const parentNode = nodeMap.get(normalizedParent);
   164→      if (parentNode) {
   165→        parentNode.children.push(node);
   166→      } else {
   167→        roots.push(node);
   168→      }
   169→    }
   170→  }
   171→
   172→  function sortNodes(nodes: PostNode[]): void {
   173→    nodes.sort((a, b) => {
   174→      const at = new Date(a.entry.meta.createdAt || 0).getTime();
   175→      const bt = new Date(b.entry.meta.createdAt || 0).getTime();
   176→      return at - bt;
   177→    });
   178→    for (const n of nodes) sortNodes(n.children);
   179→  }
   180→
   181→  sortNodes(roots);
   182→  return roots;
   183→}
   184→
   185→interface FlatPost {
   186→  entry: PostEntry;
   187→  depth: number;
   188→}
   189→
   190→function flattenTree(nodes: PostNode[], depth: number): FlatPost[] {
   191→  const result: FlatPost[] = [];
   192→  for (const node of nodes) {
   193→    result.push({ entry: node.entry, depth });
   194→    result.push(...flattenTree(node.children, depth + 1));
   195→  }
   196→  return result;
   197→}
