   556→        if (targetEl) {
   557→          // Find the end of the reply thread (last element belonging to this post's thread)
   558→          let insertAfter: Element = targetEl;
   559→          const targetDepth = parseInt(targetEl.getAttribute("data-depth") ?? "0");
   560→          let next = targetEl.nextElementSibling as HTMLElement | null;
   561→          while (next) {
   562→            const nd = parseInt(next.getAttribute("data-depth") ?? "0");
   563→            if (nd > targetDepth) {
   564→              insertAfter = next;
   565→              next = next.nextElementSibling as HTMLElement | null;
   566→            } else {
   567→              break;
   568→            }
   569→          }
   570→          container.insertBefore(inputWrapper, insertAfter.nextSibling);
   571→        } else {
