     3→declare namespace Cypress {
     4→  interface Chainable {
     5→    login(username: string): Chainable<void>;
     6→    logout(): Chainable<void>;
     7→    openWorkspace(workspace: string): Chainable<void>;
     8→    createWorkspace(workspace: string): Chainable<void>;
     9→    deleteWorkspace(workspace: string): Chainable<void>;
    10→    openChannel(channel: string): Chainable<void>;
    11→    createChannel(channel: string): Chainable<void>;
    12→    deleteChannel(channel: string): Chainable<void>;
    13→    createPost(post: string): Chainable<void>;
    14→    getPost(post: string): Chainable<JQuery<Element>>;
    15→    replyToPost(reply: string): Chainable<void>;
    16→    reactToPost(reaction: string): Chainable<void>;
    17→  }
    18→}
    19→
    20→/**
    21→ * Login using given username.
    22→ * Assumes that no one is currently logged in (login modal is showing).
    23→ */
    24→Cypress.Commands.add("login", (username: string) => {
    25→  cy.get("[data-cy='username-input']").type(username);
    26→  cy.get("[data-cy='login-btn']").click();
    27→  // Wait for the username to appear in the header
    28→  cy.get("[data-cy='current-user']").should("have.text", username);
    29→});
    30→
    31→/**
    32→ * Logout the currently logged in user.
    33→ * Assumes that a user is currently logged in.
    34→ */
    35→Cypress.Commands.add("logout", () => {
    36→  cy.get("[data-cy='logout-btn']").click();
    37→  // Wait for the login modal input to reappear
    38→  cy.get("[data-cy='username-input']").should("be.visible");
    39→});
    40→
    41→/**
    42→ * Open a workspace.
    43→ * Assumes someone is logged in and the workspace exists.
    44→ */
    45→Cypress.Commands.add("openWorkspace", (workspace: string) => {
    46→  cy.contains("[data-cy='workspace-open']", workspace).click();
    47→  cy.contains(workspace).should("exist");
    48→});
    49→
    50→/**
    51→ * Create a workspace.
    52→ * Assumes someone is logged in and the workspace does not exist.
    53→ */
    54→Cypress.Commands.add("createWorkspace", (workspace: string) => {
    55→  cy.get("[data-cy='workspace-input']").type(workspace);
    56→  cy.get("[data-cy='workspace-create-btn']").click();
    57→});
    58→
    59→/**
    60→ * Delete a workspace.
    61→ * Assumes someone is logged in and the workspace exists.
    62→ */
    63→Cypress.Commands.add("deleteWorkspace", (workspace: string) => {
    64→  cy.get(`[data-cy='workspace-delete'][data-name="${workspace}"]`).click();
    65→});
    66→
    67→/**
    68→ * Open a channel.
    69→ * Assumes someone is logged in, a workspace is open, and the channel exists.
    70→ */
    71→Cypress.Commands.add("openChannel", (channel: string) => {
    72→  cy.contains("[data-cy='channel-open']", channel).click();
    73→  cy.contains(channel).should("exist");
    74→});
    75→
    76→/**
    77→ * Create a channel.
    78→ * Assumes someone is logged in, a workspace is open, and the channel does not exist.
    79→ */
    80→Cypress.Commands.add("createChannel", (channel: string) => {
    81→  cy.get("[data-cy='channel-input']").type(channel);
    82→  cy.get("[data-cy='channel-create-btn']").click();
    83→});
    84→
    85→/**
    86→ * Delete a channel.
    87→ * Assumes someone is logged in, a workspace is open, and the channel exists.
    88→ */
    89→Cypress.Commands.add("deleteChannel", (channel: string) => {
    90→  cy.get(`[data-cy='channel-delete'][data-name="${channel}"]`).click();
    91→});
    92→
    93→/**
    94→ * Create a post.
    95→ * Assumes someone is logged in, a workspace is open, and a channel is open.
    96→ */
    97→Cypress.Commands.add("createPost", (post: string) => {
    98→  cy.get("[data-cy='post-input']").type(post);
    99→  cy.get("[data-cy='post-btn']").click();
   100→});
   101→
   102→/**
   103→ * Get a post element that contains the given search text.
   104→ * Returns the enclosing post element.
   105→ */
   106→Cypress.Commands.add(
   107→  "getPost",
   108→  (searchText: string): Cypress.Chainable<JQuery<Element>> => {
   109→    return cy
   110→      .contains("[data-cy='post-content']", searchText)
   111→      .closest("[data-cy='post-item']");
   112→  },
   113→);
   114→
   115→/**
   116→ * Reply to a post (prevSubject from getPost).
   117→ * Clicks the reply button on the post, types the reply, and submits.
   118→ */
   119→Cypress.Commands.add(
   120→  "replyToPost",
   121→  { prevSubject: true },
   122→  (subject, reply: string) => {
   123→    cy.wrap(subject).find("[data-cy='reply-btn']").click();
   124→    cy.get("[data-cy='post-input']").type(reply);
   125→    cy.get("[data-cy='post-btn']").click();
   126→  },
   127→);
   128→
   129→/**
   130→ * React to a post (prevSubject from getPost).
   131→ * Clicks the reaction button for the given reaction name.
   132→ */
   133→Cypress.Commands.add(
   134→  "reactToPost",
   135→  { prevSubject: true },
   136→  (subject, reaction: string) => {
   137→    cy.wrap(subject).find(`[data-reaction="${reaction}"]`).click();
   138→  },
   139→);
