private renderPosts(): void {
  const container = this.q<HTMLElement>("[data-cy='posts-container']");
  if (!container) return;
  container.innerHTML = "";

  const tree = buildPostTree(this.posts);
  const flat = flattenTree(tree, 0);

  for (const { entry, depth } of flat) {
    container.appendChild(this.createPostElement(entry, depth));
  }

  // Move input wrapper into the right position
  const inputWrapper = this.q<HTMLElement>(".post-input-wrapper");
  if (inputWrapper) {
    if (this.replyTarget) {
      const targetEl = container.querySelector(
        `[data-path="${CSS.escape(this.replyTarget)}"]`,
      ) as HTMLElement | null;

      if (targetEl) {
        // Find the end of the reply thread (last element belonging to this post's thread)
        let insertAfter: Element = targetEl;
        const targetDepth = parseInt(targetEl.getAttribute("data-depth") ?? "0");
        let next = targetEl.nextElementSibling as HTMLElement | null;
        while (next) {
          const nd = parseInt(next.getAttribute("data-depth") ?? "0");
          if (nd > targetDepth) {
            insertAfter = next;
            next = next.nextElementSibling as HTMLElement | null;
          } else {
            break;
          }
        }
        container.insertBefore(inputWrapper, insertAfter.nextSibling);
      } else {
        container.appendChild(inputWrapper);
      }
    } else {
      container.appendChild(inputWrapper);
    }
  }

  // Auto-scroll to bottom only if near the bottom already
  const postsArea = container.parentElement;
  if (postsArea) {
    const scrollable = postsArea.querySelector<HTMLElement>(".posts-scroll") ?? postsArea;
    const nearBottom = scrollable.scrollHeight - scrollable.scrollTop - scrollable.clientHeight < 100;
    if (nearBottom) {
      scrollable.scrollTop = scrollable.scrollHeight;
    }
  }
}

