private renderPosts(): void {
  const container = this.q<HTMLElement>("[data-cy='posts-container']");
  if (!container) return;
  container.innerHTML = "";

  const tree = buildPostTree(this.posts);
  const flat = flattenTree(tree, 0);

  for (const { entry, depth } of flat) {
    container.appendChild(this.createPostElement(entry, depth));
  }

  // Auto-scroll to bottom only if near the bottom already
  const nearBottom = container.scrollHeight - container.scrollTop - container.clientHeight < 100;
  if (nearBottom) {
    container.scrollTop = container.scrollHeight;
  }
}

