// GetCollection retrieves all documents in a collection
func (h *TestHarness) GetCollection(path string, interval string) ([]interface{}, error) {
	url := "/v1/" + path
	if interval != "" {
		url += "?interval=" + interval
	}
	resp, err := h.HTTPRequest("GET", url, nil)
	if err != nil {
		return nil, err
	}
	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("get collection failed with status %d: %s", resp.StatusCode, string(resp.Body))
	}
	return resp.JSONArray()
}

// Options sends an OPTIONS request
func (h *TestHarness) Options(path string) (*HTTPResponse, error) {
	return h.HTTPRequest("OPTIONS", path, nil)
}

// GenerateTestDBName generates a unique database name for testing
func GenerateTestDBName() string {
	return fmt.Sprintf("testdb_%d", time.Now().UnixNano())
}

// GetProjectRoot returns the project root directory
func GetProjectRoot() string {
	dir, _ := os.Getwd()
	for {
		if _, err := os.Stat(filepath.Join(dir, "go.mod")); err == nil {
			return dir
		}
		parent := filepath.Dir(dir)
		if parent == dir {
			break
		}
		dir = parent
	}
	return ""

