func (s *SequentialTests) TestGetCollection() error {
	dbName := GenerateTestDBName()
	defer s.harness.DeleteDatabase(dbName)

	if err := s.harness.CreateDatabase(dbName); err != nil {
		return err
	}

	// Add multiple documents
	for i := 1; i <= 3; i++ {
		doc := map[string]interface{}{"index": i}
		if err := s.harness.PutDocument(fmt.Sprintf("%s/doc%d", dbName, i), doc); err != nil {
			return err
		}
	}

	docs, err := s.harness.GetCollection(dbName+"/", "")
	if err != nil {
		return err
	}

	if len(docs) != 3 {
		return fmt.Errorf("expected 3 documents, got %d", len(docs))
	}
	return nil
}

