    42→    42→
    43→    43→const REACTION_ICON_MAP: Record<string, string> = {
    44→    44→  smile: "mdi:emoticon-happy-outline",
    45→    45→  frown: "mdi:emoticon-sad-outline",
    46→    46→  like: "mdi:thumb-up-outline",
