    52→    52→// ---- Markdown / text rendering ----
    53→    53→
    54→    54→function escapeHtml(text: string): string {
    55→    55→  return text
    56→    56→    .replace(/&/g, "&amp;")
    57→    57→    .replace(/</g, "&lt;")
    58→    58→    .replace(/>/g, "&gt;")
    59→    59→    .replace(/"/g, "&quot;")
    60→    60→    .replace(/'/g, "&#39;");
    61→    61→}
    62→    62→
    63→    63→function renderMarkdown(raw: string): string {
    64→    64→  let i = 0;
    65→    65→  let out = "";
    66→    66→
    67→    67→  while (i < raw.length) {
    68→    68→    // Bold: **...**
    69→    69→    if (raw.startsWith("**", i)) {
    70→    70→      const end = raw.indexOf("**", i + 2);
    71→    71→      if (end !== -1) {
    72→    72→        out += `<strong>${escapeHtml(raw.substring(i + 2, end))}</strong>`;
    73→    73→        i = end + 2;
    74→    74→        continue;
    75→    75→      }
    76→    76→    }
    77→    77→
    78→    78→    // Italic: *...*  (not **)
    79→    79→    if (raw[i] === "*" && raw[i + 1] !== "*") {
    80→    80→      let end = raw.indexOf("*", i + 1);
    81→    81→      while (end !== -1 && raw[end + 1] === "*") {
    82→    82→        end = raw.indexOf("*", end + 1);
    83→    83→      }
    84→    84→      if (end !== -1) {
    85→    85→        out += `<em>${escapeHtml(raw.substring(i + 1, end))}</em>`;
    86→    86→        i = end + 1;
    87→    87→        continue;
    88→    88→      }
    89→    89→    }
    90→    90→
    91→    91→    // Link: [text](url)
    92→    92→    if (raw[i] === "[") {
    93→    93→      const closeB = raw.indexOf("]", i + 1);
    94→    94→      if (closeB !== -1 && raw[closeB + 1] === "(") {
    95→    95→        const closeP = raw.indexOf(")", closeB + 2);
    96→    96→        if (closeP !== -1) {
    97→    97→          const linkText = raw.substring(i + 1, closeB);
    98→    98→          const url = raw.substring(closeB + 2, closeP);
    99→    99→          if (!url.startsWith("javascript:") && !url.startsWith("data:")) {
   100→   100→            out += `<a href="${escapeHtml(url)}" target="_blank" rel="noopener noreferrer">${escapeHtml(linkText)}</a>`;
   101→   101→          } else {
   102→   102→            out += escapeHtml(raw.substring(i, closeP + 1));
   103→   103→          }
   104→   104→          i = closeP + 1;
   105→   105→          continue;
   106→   106→        }
   107→   107→      }
   108→   108→    }
   109→   109→
   110→   110→    // Emoji / reaction: :name:
   111→   111→    if (raw[i] === ":") {
   112→   112→      const nextColon = raw.indexOf(":", i + 1);
   113→   113→      if (nextColon !== -1) {
   114→   114→        const name = raw.substring(i + 1, nextColon);
   115→   115→        if (/^[a-z-]+$/.test(name)) {
   116→   116→          const icon = REACTION_ICON_MAP[name];
   117→   117→          if (icon) {
   118→   118→            out += `<iconify-icon icon="${icon}" aria-label="${name}"></iconify-icon>`;
   119→   119→            i = nextColon + 1;
   120→   120→            continue;
   121→   121→          }
   122→   122→        }
   123→   123→      }
   124→   124→    }
   125→   125→
   126→   126→    // Newline
   127→   127→    if (raw[i] === "\n") {
   128→   128→      out += "<br>";
   129→   129→      i++;
   130→   130→      continue;
   131→   131→    }
   132→   132→
   133→   133→    // Regular character
   134→   134→    out += escapeHtml(raw[i]);
   135→   135→    i++;
   136→   136→  }
   137→   137→
   138→   138→  return out;
   139→   139→}
