   141→   141→// ---- Post tree helpers ----
   142→   142→
   143→   143→interface PostNode {
   144→   144→  entry: PostEntry;
   145→   145→  children: PostNode[];
   146→   146→}
   147→   147→
   148→   148→function buildPostTree(posts: Map<string, PostEntry>): PostNode[] {
   149→   149→  const nodeMap = new Map<string, PostNode>();
   150→   150→
   151→   151→  for (const entry of posts.values()) {
   152→   152→    nodeMap.set(entry.path, { entry, children: [] });
   153→   153→  }
   154→   154→
   155→   155→  const roots: PostNode[] = [];
   156→   156→
   157→   157→  for (const [, node] of nodeMap) {
   158→   158→    const parent = node.entry.doc.parent ?? "";
   159→   159→    if (!parent) {
   160→   160→      roots.push(node);
   161→   161→    } else {
   162→   162→      const normalizedParent = normalizePath(parent);
   163→   163→      const parentNode = nodeMap.get(normalizedParent);
   164→   164→      if (parentNode) {
   165→   165→        parentNode.children.push(node);
   166→   166→      } else {
   167→   167→        roots.push(node);
   168→   168→      }
   169→   169→    }
   170→   170→  }
   171→   171→
   172→   172→  function sortNodes(nodes: PostNode[]): void {
   173→   173→    nodes.sort((a, b) => {
   174→   174→      const at = new Date(a.entry.meta.createdAt || 0).getTime();
   175→   175→      const bt = new Date(b.entry.meta.createdAt || 0).getTime();
   176→   176→      return at - bt;
   177→   177→    });
   178→   178→    for (const n of nodes) sortNodes(n.children);
   179→   179→  }
   180→   180→
   181→   181→  sortNodes(roots);
   182→   182→  return roots;
   183→   183→}
   184→   184→
   185→   185→interface FlatPost {
   186→   186→  entry: PostEntry;
   187→   187→  depth: number;
   188→   188→}
   189→   189→
   190→   190→function flattenTree(nodes: PostNode[], depth: number): FlatPost[] {
   191→   191→  const result: FlatPost[] = [];
   192→   192→  for (const node of nodes) {
   193→   193→    result.push({ entry: node.entry, depth });
   194→   194→    result.push(...flattenTree(node.children, depth + 1));
   195→   195→  }
   196→   196→  return result;
   197→   197→}
