    37→/**
    38→ * Normalize a document path by stripping the DATABASE_PATH prefix and any
    39→ * leading slash so we always work with e.g. "WS/channels/CH/posts/ID".
    40→ */
    41→export function normalizePath(path: string): string {
    42→  const dp = process.env.DATABASE_PATH || "";
    43→  if (dp && path.includes(dp)) {
    44→    const idx = path.indexOf(dp);
    45→    path = path.substring(idx + dp.length);
    46→  } else if (path.startsWith("/")) {
    47→    path = path.substring(1);
    48→  }
    49→  return path;
    50→}
