    27→/** Build the base database URL (host + path). */
    28→function dbUrl(): string {
    29→  return `${process.env.DATABASE_HOST}${process.env.DATABASE_PATH}`;
    30→}
    31→
    32→/** Build the auth URL (host + auth path). */
    33→function authUrl(): string {
    34→  return `${process.env.DATABASE_HOST}${process.env.AUTH_PATH}`;
    35→}
