    65→export async function login(username: string): Promise<string> {
    66→  const resp = await fetch(authUrl(), {
    67→    method: "POST",
    68→    headers: { "Content-Type": "application/json" },
    69→    body: JSON.stringify({ username }),
    70→  });
    71→  if (!resp.ok) {
    72→    throw new Error(`Login failed: ${resp.status} ${resp.statusText}`);
    73→  }
    74→  const data: unknown = await resp.json();
    75→  if (!isToken(data)) {
    76→    throw new Error("Invalid token response from server");
    77→  }
    78→  slog.info("Logged in", ["username", username]);
    79→  return data.token;
    80→}
