    85→export async function logout(token: string): Promise<void> {
    86→  const resp = await fetch(authUrl(), {
    87→    method: "DELETE",
    88→    headers: { Authorization: `Bearer ${token}` },
    89→  });
    90→  if (!resp.ok && resp.status !== 204) {
    91→    throw new Error(`Logout failed: ${resp.status} ${resp.statusText}`);
    92→  }
