   670→  private async doCreatePost(): Promise<void> {
   671→    if (!this.currentWorkspace || !this.currentChannel) return;
   672→    const textarea = this.q<HTMLTextAreaElement>("[data-cy='post-input']");
   673→    const msg = textarea.value.trim();
   674→    if (!msg) return;
   675→
   676→    const parent = this.replyTarget ?? "";
   677→    textarea.value = "";
   678→    this.resetInput();
   679→    this.renderPosts();
   680→
   681→    try {
   682→      await createPost(this.currentToken, this.currentWorkspace, this.currentChannel, msg, parent);
   683→    } catch (err) {
   684→      slog.error("Failed to create post", ["error", String(err)]);
   685→      this.showError(`Error creating post: ${String(err)}`);
   686→    }
   687→  }
   688→
   689→  // ---- Formatting buttons ----
   690→
   691→  private insertFormatting(format: string): void {
   692→    const ta = this.q<HTMLTextAreaElement>("[data-cy='post-input']");
   693→    const start = ta.selectionStart;
   694→    const end = ta.selectionEnd;
   695→    const selected = ta.value.substring(start, end);
   696→
   697→    if (format === "link") {
   698→      if (selected) {
   699→        ta.value =
   700→          ta.value.substring(0, start) + `[${selected}](url)` + ta.value.substring(end);
   701→        ta.selectionStart = ta.selectionEnd = start + selected.length + 3;
   702→      } else {
   703→        ta.value = ta.value.substring(0, start) + "[](url)" + ta.value.substring(end);
   704→        ta.selectionStart = ta.selectionEnd = start + 1;
   705→      }
   706→      ta.focus();
   707→      return;
   708→    }
   709→
   710→    let wrap = "";
   711→    let extra = 0;
   712→    if (format === "bold") {
   713→      wrap = "**";
   714→      extra = 4;
   715→    } else if (format === "italic") {
   716→      wrap = "*";
   717→      extra = 2;
   718→    } else {
   719→      return;
   720→    }
   721→
   722→    ta.value =
   723→      ta.value.substring(0, start) + wrap + selected + wrap + ta.value.substring(end);
   724→    ta.selectionStart = ta.selectionEnd = selected ? end + extra : start + extra / 2;
   725→    ta.focus();
   726→  }
   727→
   728→  private insertEmoji(emoji: string): void {
   729→    const ta = this.q<HTMLTextAreaElement>("[data-cy='post-input']");
   730→    const pos = ta.selectionStart;
   731→    ta.value = ta.value.substring(0, pos) + emoji + ta.value.substring(pos);
   732→    ta.selectionStart = ta.selectionEnd = pos + emoji.length;
   733→    ta.focus();
   734→  }
