private async doCreatePost(): Promise<void> {
  if (!this.currentWorkspace || !this.currentChannel) return;
  const textarea = this.q<HTMLTextAreaElement>("[data-cy='post-input']");
  const msg = textarea.value.trim();
  if (!msg) return;

  const parent = this.replyTarget ?? "";
  textarea.value = "";
  this.resetInput();

  // Optimistic update: show post immediately without waiting for SSE
  const tempPath = `${this.currentWorkspace}/channels/${this.currentChannel}/posts/_opt_${Date.now()}`;
  const optimisticEntry: PostEntry = {
    path: tempPath,
    doc: { msg, parent: parent || undefined, reactions: {} },
    meta: { createdAt: Date.now(), createdBy: this.currentUser },
  };
  this.posts.set(tempPath, optimisticEntry);
  this.renderPosts();

  try {
    const createdPath = await createPost(
      this.currentToken,
      this.currentWorkspace,
      this.currentChannel,
      msg,
      parent,
    );
    // Replace optimistic entry with the real one (SSE will also update it)
    this.posts.delete(tempPath);
    if (createdPath && !this.posts.has(createdPath)) {
      this.posts.set(createdPath, {
        path: createdPath,
        doc: { msg, parent: parent || undefined, reactions: {} },
        meta: { createdAt: Date.now(), createdBy: this.currentUser },
      });
    }
    this.renderPosts();
  } catch (err) {
    // Remove optimistic entry on failure
    this.posts.delete(tempPath);
    this.renderPosts();
    slog.error("Failed to create post", ["error", String(err)]);
    this.showError(`Error creating post: ${String(err)}`);
  }
}

