  // Wait for the login modal input to reappear
  cy.get("[data-cy='username-input']").should("be.visible");
});

/**
 * Open a workspace by name.
 * If the workspace button exists in the sidebar, clicks it and waits for it to open.
 * Otherwise, uses the hidden workspace-open-input (e.g. for non-existent workspace error tests).
